    @Override
    public void setupAnim(T entity, float limbSwing, float limbSwingAmount, float ageInTicks, float netHeadYaw, float headPitch) {
        // Generated stub. Add animation logic here.

        this.head.yRot = netHeadYaw * ((float)Math.PI / 180F);
        this.head.xRot = headPitch * ((float)Math.PI / 180F);

        float swing = (float)Math.cos(limbSwing * 0.6662F);
        float swingOpp = (float)Math.cos(limbSwing * 0.6662F + (float)Math.PI);
        this.right_leg.xRot = swing * 1.4F * limbSwingAmount;
        this.left_leg.xRot = swingOpp * 1.4F * limbSwingAmount;
        this.right_arm.xRot = swingOpp * 1.0F * limbSwingAmount;
        this.left_arm.xRot = swing * 1.0F * limbSwingAmount;
    }

